(function() {
  const ctx = document.getElementById('mainChart').getContext('2d');
  const models = ['GPT-4o', 'Claude 3.5', 'o1-mini', 'Llama-3.1-8B', 'Llama-3.3-70B'];

  new Chart(ctx, {
    type: 'bar',
    data: {
      labels: models,
      datasets: [
        {
          label: 'No Planning',
          data: [0.19, 0.19, 0.29, 0.10, 0.20],
          backgroundColor: '#e2e8f0',
          borderRadius: 4
        },
        {
          label: 'CoT',
          data: [0.32, 0.24, 0.33, 0.14, 0.27],
          backgroundColor: '#f6ad55',
          borderRadius: 4
        },
        {
          label: 'ReAct',
          data: [0.34, 0.30, 0.38, 0.16, 0.30],
          backgroundColor: '#4dabf7',
          borderRadius: 4
        },
        {
          label: 'Gold Planning',
          data: [0.50, 0.50, 0.62, 0.34, 0.47],
          backgroundColor: '#51cf66',
          borderRadius: 4
        }
      ]
    },
    options: {
      animation: false,
      responsive: true,
      maintainAspectRatio: true,
      scales: {
        y: {
          beginAtZero: true,
          max: 0.7,
          ticks: {
            callback: function(v) { return (v * 100).toFixed(0) + '%'; },
            font: { size: 11 }
          },
          grid: { color: '#e2e8f0' },
          title: {
            display: true,
            text: 'Prometheus-2 Score (normalised)',
            font: { size: 12 }
          }
        },
        x: {
          grid: { display: false },
          ticks: { font: { size: 11 } }
        }
      },
      plugins: {
        legend: {
          position: 'top',
          labels: { font: { size: 11 }, usePointStyle: true, pointStyle: 'rectRounded' }
        },
        tooltip: {
          callbacks: {
            label: function(c) {
              return c.dataset.label + ': ' + (c.parsed.y * 100).toFixed(0) + '%';
            }
          }
        }
      }
    }
  });
})();
